// patient-app/src/api.js
//
// FIX: Added GOOGLE_CLIENT_ID export — it was imported in LoginScreen.js
// line 13 but was never exported from this file, causing a crash when
// the Google login button was tapped.
//
// FIX: Standardized on EXPO_PUBLIC_API_BASE_URL throughout.

import axios from "axios";

// ── Base URLs ─────────────────────────────────────────────────────────────────
export const API_BASE_URL =
  process.env.EXPO_PUBLIC_API_BASE_URL ||
  "http://localhost:8000/api/v1";

export const WS_BASE_URL =
  process.env.EXPO_PUBLIC_WS_URL ||
  API_BASE_URL.replace(/^https/, "wss").replace(/^http/, "ws").replace(/\/api\/v1\/?$/, "");

// ── FIX: Export GOOGLE_CLIENT_ID ──────────────────────────────────────────────
// Add EXPO_PUBLIC_GOOGLE_CLIENT_ID to your patient-app/.env file.
// Get the client ID from Google Cloud Console → APIs & Services → Credentials.
export const GOOGLE_CLIENT_ID =
  process.env.EXPO_PUBLIC_GOOGLE_CLIENT_ID || "";

// ── Axios instance ────────────────────────────────────────────────────────────
const api = axios.create({
  baseURL: API_BASE_URL,
  timeout: 15000,
  headers: {
    "Content-Type": "application/json",
  },
});

// ── Request interceptor: attach token ────────────────────────────────────────
api.interceptors.request.use(
  (config) => {
    // AsyncStorage is accessed via the service layer — token injected there.
    return config;
  },
  (error) => Promise.reject(error)
);

export default api;
